#!/usr/bin/env node
// Patch Tauri's generated Gradle task to call the local Tauri CLI directly
// instead of routing Cargo flags back through node or pnpm.

import { existsSync, readFileSync, readdirSync, statSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const appDir = dirname(dirname(fileURLToPath(import.meta.url)));
const androidRoot = join(appDir, 'src-tauri/gen/android');

function findBuildTask(dir) {
  if (!existsSync(dir)) return null;
  for (const entry of readdirSync(dir)) {
    const full = join(dir, entry);
    if (statSync(full).isDirectory()) {
      const found = findBuildTask(full);
      if (found) return found;
    } else if (entry === 'BuildTask.kt') {
      return full;
    }
  }
  return null;
}

const buildTaskPath = findBuildTask(join(androidRoot, 'buildSrc'));

if (!buildTaskPath) {
  console.error(
    `[patch-android-build-task] BuildTask.kt not found under ${androidRoot}/buildSrc\n` +
      'Run `tauri android init` first.',
  );
  process.exit(1);
}

let source = readFileSync(buildTaskPath, 'utf8');
const afterExecutable = '        val executable = """tauri""";';
const afterArgs = '        val args = listOf("android", "android-studio-script");';
const executablePattern = /^        val executable = """.*""";$/m;
const argsPattern = /^        val args = listOf\((?:"[^"]+",?\s*)+\);$/m;

if (source.includes(afterExecutable) && source.includes(afterArgs)) {
  console.log('[patch-android-build-task] already patched.');
  process.exit(0);
}

if (!executablePattern.test(source) || !argsPattern.test(source)) {
  console.error('[patch-android-build-task] generated task shape changed; refusing to guess.');
  process.exit(1);
}

source = source
  .replace(executablePattern, afterExecutable)
  .replace(argsPattern, afterArgs);

writeFileSync(buildTaskPath, source);
console.log('[patch-android-build-task] Gradle rust task now calls tauri directly.');
